-- Ken's Hardened V2 Fix

local b64_0xlllII1 = {}
local char_0xl1lI1I='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xllllll=1,#char_0xl1lI1I do b64_0xlllII1[char_0xl1lI1I:sub(i_0xllllll,i_0xllllll)] = i_0xllllll - 1 end

function b64_0xlllII1.dec_0xllIIII(d_0xll1lII)
    d_0xll1lII = string.gsub(d_0xll1lII, '[^'..char_0xl1lI1I..'=]', '')
    local r_0xlII1ll = {}
    for i_0xllllll=1, #d_0xll1lII, 4 do
        local c_0xlIlIIl = b64_0xlllII1[d_0xll1lII:sub(i_0xllllll,i_0xllllll)] or 0
        local c_0xl11Il1 = b64_0xlllII1[d_0xll1lII:sub(i_0xllllll+1,i_0xllllll+1)] or 0
        local c_0x1lIlII, c_0x1lI1Il = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xll1lII:sub(i_0xllllll+2,i_0xllllll+2)
        if ch3 == "=" then has3 = false else c_0x1lIlII = b64_0xlllII1[ch3] or 0 end
        local ch4 = d_0xll1lII:sub(i_0xllllll+3,i_0xllllll+3)
        if ch4 == "=" then has4 = false else c_0x1lI1Il = b64_0xlllII1[ch4] or 0 end
        local b_0xl1I11I = c_0xlIlIIl * (2^18) + c_0xl11Il1 * (2^12) + c_0x1lIlII * (2^6) + c_0x1lI1Il
        local b_0x111IIl = math.floor(b_0xl1I11I / (2^16)) % (2^8)
        local b_0xlIl1l1 = math.floor(b_0xl1I11I / (2^8)) % (2^8)
        local b_0xI11IlI = b_0xl1I11I % (2^8)
        table.insert(r_0xlII1ll, string.char(b_0x111IIl))
        if has3 then table.insert(r_0xlII1ll, string.char(b_0xlIl1l1)) end
        if has4 then table.insert(r_0xlII1ll, string.char(b_0xI11IlI)) end
    end
    return table.concat(r_0xlII1ll)
end


local function bxor_0x11llIl(a_0xlll11l,b_0xllIIIl)
    if bit32 then return bit32.bxor(a_0xlll11l,b_0xllIIIl) end
    local r_0xIIlll1 = 0
    for i_0xIIl1II = 0, 7 do
        local x_0xlI1111 = a_0xlll11l % 2
        local y_0x1Ill1I = b_0xllIIIl % 2
        if x_0xlI1111 ~= y_0x1Ill1I then r_0xIIlll1 = r_0xIIlll1 + (2^i_0xIIl1II) end
        a_0xlll11l = math.floor(a_0xlll11l / 2)
        b_0xllIIIl = math.floor(b_0xllIIIl / 2)
    end
    return r_0xIIlll1
end


local function bxor_str_0xIlllI1(s_0xlIl11I, k_0xIIll11)
    local r_0xIlIllI = {}
    for i_0xllIlll=1, #s_0xlIl11I do
        local b_0xI1ll1I = string.byte(s_0xlIl11I, i_0xllIlll)
        local kb_0xlll1ll = string.byte(k_0xIIll11, (i_0xllIlll-1) % #k_0xIIll11 + 1)
        r_0xIlIllI[i_0xllIlll] = string.char(bxor_0x11llIl(b_0xI1ll1I, kb_0xlll1ll))
    end
    return table.concat(r_0xIlIllI)
end


local function getkeys_0xI1lIlI()
    local seed = b64_0xlllII1.dec_0xllIIII("aFBBQUFwbHA=")
    local k1_enc = b64_0xlllII1.dec_0xllIIII("ESYwLysALUc=")
    local k2_enc = b64_0xlllII1.dec_0xllIIII("Iip5LilIAwo=")
    return bxor_str_0xIlllI1(k1_enc, seed), bxor_str_0xIlllI1(k2_enc, seed)
end


local function cff_0xlI1I1I(a_0xI11IIl)
    local st_0x1llIII = 0
    local res_0xIlIlII = a_0xI11IIl
    while true do
        if st_0x1llIII == 0 then
            res_0xIlIlII = res_0xIlIlII + 1
            st_0x1llIII = 1
        elseif st_0x1llIII == 1 then
            res_0xIlIlII = res_0xIlIlII * 2
            st_0x1llIII = 2
        elseif st_0x1llIII == 2 then
            res_0xIlIlII = res_0xIlIlII - 3
            st_0x1llIII = 3
        else
            break
        end
    end
    return res_0xIlIlII
end


local function chain_0xIIIIlI(x) return x*2 end
local function chain_0xlIIll1(x) return chain_0xIIIIlI(x)+1 end


local d_0xlIIIIl = {
  {op=255, val="", is_enc=true},
}
local pc_0xI1Illl = 1
local stk_0xlllI1I = {}
stk_0xlllI1I._jmp = nil


local disp_0xIllIlI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xI1lIlI()

local state_0x1lIIll = 0
while true do
    if state_0x1lIIll == 0 then  -- FETCH
        if pc_0xI1Illl > #d_0xlIIIIl then break end
        local inst = d_0xlIIIIl[pc_0xI1Illl]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlllII1.dec_0xllIIII(val)
            d = bxor_str_0xIlllI1(d, k2)
            val = bxor_str_0xIlllI1(d, k1)
        end
        stk_0xlllI1I._jmp = nil
        pc_0xI1Illl = pc_0xI1Illl + 1
        cur_op_0xIIIllI = opcode
        cur_val_0xIllI1l = val
        state_0x1lIIll = 1

    elseif state_0x1lIIll == 1 then  -- EXECUTE
        local handler = disp_0xIllIlI[cur_op_0xIIIllI]
        if handler then
            handler(stk_0xlllI1I, cur_val_0xIllI1l)
        end
        if stk_0xlllI1I._jmp then
            pc_0xI1Illl = pc_0xI1Illl + stk_0xlllI1I._jmp
        end
        state_0x1lIIll = 0
    else
        break
    end
end
